mapper.select:
SELECT COUNT(*)
FROM CHILD_INVITE
WHERE invite_code = #{inviteCode}

SELECT invite_id
FROM CHILD_INVITE
WHERE invite_code = #{inviteCode}

mapper.update:
UPDATE CHILD_INVITE
SET parent_id = #{parentId}
WHERE invite_code = #{inviteCode}

mapper.select:
SELECT frame_id
FROM FRAME
WHERE frame_type = #{frameType}

mapper.update:
UPDATE CHILD
SET frame_id = (
    SELECT frame_id
    FROM FRAME
    WHERE frame_type = #{frameType}
)
WHERE child_id = #{childId}
  AND EXISTS (
    SELECT 1
    FROM FRAME
    WHERE frame_type = #{frameType}
  )

UPDATE CHILD
SET frame_id = #{frameId}
WHERE child_id = #{childId}
  AND EXISTS (
    SELECT 1
    FROM FRAME
    WHERE frame_id = #{frameId}
  )

UPDATE CHILD_INVITE
SET invite_code = #{inviteCode},
    regenerated_at = SYSTIMESTAMP
WHERE invite_id = (
    SELECT invite_id
    FROM CHILD
    WHERE child_id = #{childId}
      AND parent_id = #{parentId}
)

mapper.delete:
DELETE FROM NOTIFICATION
WHERE child_id = #{childId}
   OR submission_id IN (
        SELECT submission_id FROM MISSION_SUBMISSION WHERE child_id = #{childId}
   )
   OR mission_id IN (
        SELECT mission_id FROM MISSION WHERE child_id = #{childId}
   )
   OR reward_id IN (
        SELECT reward_id FROM REWARD_HISTORY WHERE child_id = #{childId}
   )

DELETE FROM PET_INTERACTION_COOLDOWN
WHERE child_pet_id IN (
    SELECT child_pet_id
    FROM CHILD_PET
    WHERE child_id = #{childId}
)
